function calculateVoltage(input) {
    // Initialize an array to hold the boolean results
    const results = [];

    // Split the input string into an array of values
    const values = input.split(',');

    // Iterate through each value
    for (let i = 0; i < values.length; i++) {
        // Parse the value as a float
        const voltage = parseFloat(values[i]);

        // Check if the voltage is within a valid range (for example, 0 to 5 volts)
        if (voltage >= 0 && voltage <= 5) {
            results.push(true);  // Valid voltage
        } else {
            results.push(false); // Invalid voltage
        }
    }

    // Return the array of boolean results
    return results;
}

